const traces = [];

// ---- ROW 1 ----
// 1. Line/Scatter (Row 0, Col 0 -> x, y)
traces.push({ type: 'scatter', mode: 'lines+markers', x: [1, 2, 3, 4, 5], y: [2, 4, 1, 5, 3], name: 'Scatter', xaxis: 'x', yaxis: 'y', line: { color: '#0ea5e9', width: 3 }, marker: { size: 8 } });

// 2. Bar (Row 0, Col 1 -> x2, y2)
traces.push({ type: 'bar', x: ['Apples', 'Oranges', 'Bananas'], y: [10, 15, 7], xaxis: 'x2', yaxis: 'y2', marker: { color: ['#ef4444', '#f97316', '#eab308'] } });

// 3. Heatmap (Row 0, Col 2 -> x3, y3)
traces.push({ type: 'heatmap', z: [[1, 20, 30], [20, 1, 60], [30, 60, 1]], xaxis: 'x3', yaxis: 'y3', colorscale: 'Viridis' });

// 4. Pie / Donut (Row 0, Col 3 -> domain)
traces.push({ type: 'pie', labels: ['O', 'H', 'C', 'N'], values: [45, 25, 20, 10], domain: { row: 0, column: 3 }, hole: 0.4 });

// ---- ROW 2 ----
// 5. Box Plot (Row 1, Col 0 -> x5, y5)
traces.push({ type: 'box', y: [1, 2, 3, 4, 4, 4, 5, 5, 6, 8, 9, 2, 2, 1], xaxis: 'x5', yaxis: 'y5', marker: { color: '#10b981' } });

// 6. Treemap (Row 1, Col 1 -> domain)
traces.push({ type: 'treemap', labels: ['Root', 'A', 'B', 'B1', 'B2', 'C'], parents: ['', 'Root', 'Root', 'B', 'B', 'Root'], values: [50, 14, 22, 10, 12, 14], domain: { row: 1, column: 1 }, textinfo: 'label+value' });

// 7. Contour Plot (Row 1, Col 2 -> x7, y7)
traces.push({ type: 'contour', z: [[10, 10.6, 12, 11], [10.6, 12, 10, 13], [12, 10, 10.6, 11], [11, 13, 11, 12]], xaxis: 'x7', yaxis: 'y7', colorscale: 'Jet' });

// 8. Area Chart (Row 1, Col 3 -> x8, y8)
traces.push({ type: 'scatter', mode: 'none', fill: 'tozeroy', x: [1, 2, 3, 4], y: [1, 3, 2, 5], xaxis: 'x8', yaxis: 'y8', fillcolor: 'rgba(168, 85, 247, 0.5)' });

// ---- ROW 3 ----
// 9. Violin Plot (Row 2, Col 0 -> x9, y9)
traces.push({ type: 'violin', y: [2, 2, 3, 4, 5, 5, 5, 6, 7, 7, 8, 9, 10], xaxis: 'x9', yaxis: 'y9', box: { visible: true }, line: { color: '#ffffff' }, fillcolor: '#f43f5e' });

// 10. Histogram (Row 2, Col 1 -> x10, y10)
traces.push({ type: 'histogram', x: [1, 1, 1, 2, 2, 3, 4, 4, 4, 4, 5, 5], xaxis: 'x10', yaxis: 'y10', marker: { color: '#3b82f6' } });

// 11. Waterfall (Row 2, Col 2 -> x11, y11)
traces.push({ type: 'waterfall', x: ['Sales', 'Consulting', 'Returns', 'Net'], y: [60, 20, -15, 65], measure: ['relative', 'relative', 'relative', 'total'], xaxis: 'x11', yaxis: 'y11', decreaser: {marker:{color: '#ef4444'}}, increaser: {marker:{color: '#10b981'}}, totals: {marker:{color: '#3b82f6'}} });

// 12. Funnel (Row 2, Col 3 -> x12, y12)
traces.push({ type: 'funnel', y: ['Website Visits', 'Downloads', 'Purchases'], x: [1200, 300, 45], xaxis: 'x12', yaxis: 'y12' });

// ---- ROW 4 ----
// 13. Bubble Chart (Row 3, Col 0 -> x13, y13)
traces.push({ type: 'scatter', mode: 'markers', x: [1, 2, 3, 4], y: [10, 11, 12, 13], marker: { size: [40, 60, 80, 100], color: [1, 2, 3, 4], colorscale: 'Bluered' }, xaxis: 'x13', yaxis: 'y13' });

// 14. Candlestick (Row 3, Col 1 -> x14, y14)
traces.push({ type: 'candlestick', x: ['2023-01', '2023-02', '2023-03'], close: [110, 130, 120], high: [120, 140, 130], low: [100, 110, 110], open: [105, 120, 125], xaxis: 'x14', yaxis: 'y14' });

// 15. OHLC (Row 3, Col 2 -> x15, y15)
traces.push({ type: 'ohlc', x: ['2023-01', '2023-02', '2023-03'], close: [110, 130, 120], high: [120, 140, 130], low: [100, 110, 110], open: [105, 120, 125], xaxis: 'x15', yaxis: 'y15' });

// 16. Sunburst (Row 3, Col 3 -> domain)
traces.push({ type: 'sunburst', labels: ['Root', 'A', 'B', 'A1', 'A2', 'C'], parents: ['', 'Root', 'Root', 'A', 'A', 'Root'], values: [50, 14, 22, 10, 4, 14], domain: { row: 3, column: 3 } });

// ---- ROW 5 ----
// 17. Radar (Row 4, Col 0 -> polar)
traces.push({ type: 'scatterpolar', r: [39, 28, 8, 7, 28, 39], theta: ['A','B','C', 'D', 'E', 'A'], fill: 'toself', subplot: 'polar' });

// 18. Polar Bar (Row 4, Col 1 -> polar2)
traces.push({ type: 'barpolar', r: [3.5, 1.5, 2.5, 4.5, 4.5, 4, 3], theta: [65, 15, 210, 110, 312, 180, 270], subplot: 'polar2' });

// 19. Density 2D (Row 4, Col 2 -> x19, y19)
traces.push({ type: 'histogram2dcontour', x: [1,1,1,2,2,3,4,4,4,5], y: [1,2,2,1,2,2,3,4,4,5], xaxis: 'x19', yaxis: 'y19' });

// 20. Indicator Gauge (Row 4, Col 3 -> domain)
traces.push({ type: 'indicator', mode: 'gauge+number', value: 380, gauge: { axis: { range: [null, 500] } }, domain: { row: 4, column: 3 } });

return traces;
